# Check: safety baseline present and at minimum version
import re, yaml, pathlib, sys

MIN_VERSION = (2, 1)
PATTERN = re.compile(r"safety baseline v(\d+)\.(\d+)", re.IGNORECASE)

def check_safety_baseline(path: pathlib.Path) -> str | None:
    data = yaml.safe_load(path.read_text())
    system = data.get("system", "")
    m = PATTERN.search(system)
    if not m:
        return f"{path}: BLOCKING — safety baseline not found in system prompt"
    major, minor = int(m.group(1)), int(m.group(2))
    if (major, minor) < MIN_VERSION:
        return (
            f"{path}: BLOCKING — safety baseline v{major}.{minor} "
            f"is below minimum v{MIN_VERSION[0]}.{MIN_VERSION[1]}"
        )
    return None

errors = [
    check_safety_baseline(p)
    for p in pathlib.Path("prompts/").glob("**/*.yaml")
    if (err := check_safety_baseline(p))
]
for e in [e for e in errors if e]:
    print(f"::error::{e}")
sys.exit(1 if any(errors) else 0)

# scripts/check_all_blocking_criteria.py
# Orchestrates all six criteria checks and produces a summary.
import subprocess, sys, json, pathlib

CRITERIA = [
    {
        "id": 1,
        "name": "Safety baseline present",
        "script": "scripts/check_safety_baseline.py",
        "waiverable": False,
    },
    {
        "id": 2,
        "name": "Adversarial evals 100%",
        "script": "scripts/check_adversarial_evals.py",
        "waiverable": False,
    },
    {
        "id": 3,
        "name": "Version bump correct",
        "script": "scripts/check_versions.py",
        "waiverable": False,
    },
    {
        "id": 4,
        "name": "Overall eval >= threshold",
        "script": "scripts/check_eval_thresholds.py",
        "waiverable": True,   # MEDIUM/LOW only, with waiver ticket
    },
    {
        "id": 5,
        "name": "No hardcoded secrets",
        "script": "scripts/check_secrets.py",
        "waiverable": False,
    },
    {
        "id": 6,
        "name": "No HIGH/CRITICAL security findings",
        "script": "scripts/check_security_findings.py",
        "waiverable": False,
    },
]

failures = []
for criterion in CRITERIA:
    result = subprocess.run(
        ["python", criterion["script"]],
        capture_output=True, text=True
    )
    if result.returncode != 0:
        waiver_note = "(waiver available — see waiver process)" if criterion["waiverable"] else "(NO WAIVER)"
        failures.append({
            "id": criterion["id"],
            "name": criterion["name"],
            "waiverable": criterion["waiverable"],
            "output": result.stdout.strip(),
        })
        print(f"::error::Criterion {criterion['id']} FAILED {waiver_note}: {criterion['name']}")
        if result.stdout:
            print(result.stdout)

if failures:
    non_waiverable = [f for f in failures if not f["waiverable"]]
    waiverable     = [f for f in failures if f["waiverable"]]
    print(f"\n{len(non_waiverable)} non-waiverable failure(s) — HARD BLOCK")
    print(f"{len(waiverable)} waiverable failure(s) — requires waiver ticket")
    sys.exit(1)
else:
    print("All 6 release-blocking criteria passed ✓")
    sys.exit(0)
